#include <iostream>
using namespace std;

void reverseArray(int* arr, int size) {
    int* left = arr;
    int* right = arr + size - 1;
    while (left < right) {
        int temp = *left;
        *left = *right;
        *right = temp;
        left++;
        right--;
    }
}

void printArray(int* arr, int size) {
    for (int* p = arr; p < arr + size; p++) {
        cout << *p << " ";
    }
    cout << endl;
}

int main() {
    int arr[] = {1, 2, 3, 4, 5};
    int size = 5;
    cout << "Before: ";
    printArray(arr, size);
    reverseArray(arr, size);
    cout << "After: ";
    printArray(arr, size);
    return 0;
}

#include <iostream>
using namespace std;

int strLen(const char* str) {
    const char* p = str;
    while (*p != '\0') {
        p++;
    }
    return p - str;
}

int main() {
    const char* s = "Modern Age Coders";
    cout << "Length: " << strLen(s) << endl;

    const char* empty = "";
    cout << "Length of empty: " << strLen(empty) << endl;
    return 0;
}

#include <iostream>
