void swapPointers(int** pp1, int** pp2) {
    int* temp = *pp1;
    *pp1 = *pp2;
    *pp2 = temp;
}

int main() {
    int a = 10, b = 20;
    int* p1 = &a;
    int* p2 = &b;

    cout << "Before: *p1=" << *p1 << ", *p2=" << *p2 << endl;
    swapPointers(&p1, &p2);
    cout << "After: *p1=" << *p1 << ", *p2=" << *p2 << endl;

    // Verify a and b are unchanged
    cout << "a=" << a << ", b=" << b << endl;
    return 0;
}

#include <iostream>
using namespace std;

void findMinMax(int* arr, int size, int* min, int* max) {
    *min = *arr;
    *max = *arr;
    for (int* p = arr + 1; p < arr + size; p++) {
        if (*p < *min) *min = *p;
        if (*p > *max) *max = *p;
    }
}

int main() {
    int arr[] = {34, 12, 56, 7, 89, 23};
    int min, max;
    findMinMax(arr, 6, &min, &max);
    cout << "Min: " << min << endl;
    cout << "Max: " << max << endl;
    return 0;
}

